mapper.sql:
SELECT t.ID, t.DEBTORPAYMENT_NO, t.COMPANY_ID, t.COMPANY_NAME, t.CUSTOMER_ID, t.CUSTOMER_NAME, t.DEBTORPAYMENT_TIME, t.AMOUNT, t.STATUS, t.REMARK, t.VOID_REMARK, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.PREPAYMENT_TYPE_CODE, t.PREPAYMENT_TYPE_NAME FROM T_FD_DEBTORPAYMENT t LEFT JOIN T_FD_DEBTORPAYMENT_DETAIL t1 ON t.ID = t1.DEBTORPAYMENT_ID
and t.ID = #{id}
and t.PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode}
and t.STATUS = #{status}
and t.DEBTORPAYMENT_NO LIKE #{debtorpaymentNoBind}
and t.COMPANY_ID = #{companyId}
and t.CUSTOMER_ID = #{customerId}
and t.DEBTORPAYMENT_TIME = #{debtorpaymentTime}
and t1.SYS_INVOICE_PREPAY_NO LIKE #{sysInvoicePrepayNoBind}
and t1.INVOICE_PREPAY_NO LIKE #{invoicePrepayNoBind}
GROUP BY t.ID, t.DEBTORPAYMENT_NO, t.COMPANY_ID, t.COMPANY_NAME, t.CUSTOMER_ID, t.CUSTOMER_NAME, t.DEBTORPAYMENT_TIME, t.AMOUNT, t.STATUS, t.REMARK, t.VOID_REMARK, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.PREPAYMENT_TYPE_CODE, t.PREPAYMENT_TYPE_NAME ORDER BY CREATE_TIME DESC

mapper.select:
SELECT TFBCP.ID, TFBCP.ID AS invoicePrepayId, TFBCP.PREPAYMENT_CODE AS sysInvoicePrepayNo, TFBCP.DEBTORPAYMENT_ID, TFBCP.SOURCE_DEBTORPAYMENT_ID, TFBCP.COMPANY_NAME, TFBCP.COMPANY_ID, TFBCP.CUSTOMER_ID, TFBCP.CUSTOMER_NAME AS customerName, TFBCP.PREPAYMENT_TIME AS invoicePrepayTime, NVL(TFBCP.PREPAYMENT_AMOUNT,0)-NVL(TFBCP.UTILIZED_AMOUNT,0) AS invoicePrepayAmount, TFBCP.UTILIZED_AMOUNT, TFBCP.PAYMENT_METHOD_CODE AS paymentMethodCode, TFBCP.PAYMENT_METHOD_NAME AS paymentMethodName, TFBCP.PREPAY_MODE_CODE, TFBCP.BANK_NAME, TFBCP.BANK_ID, TFBCP.STATUS, TFBCP.REMARK, TFBCP.CREATE_BY, TFBCP.CREATE_BY_NAME, TFBCP.CREATE_TIME, TFBCP.UPDATE_BY, TFBCP.UPDATE_BY_NAME, TFBCP.UPDATE_TIME, TFBCP.CARGO_INFO_ID, case when tbci.id is not null then to_char(tbci.cargo_info_no || '_' || tbt.trust_no) else '' end "cargoInfoNo"
FROM T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP left join t_bus_cargo_info tbci on tbci.id = TFBCP.cargo_info_id left join t_bus_trust tbt on tbt.id = TFBCP.bus_trust_id
TFBCP.STATUS = 1 AND NVL(TFBCP.PREPAYMENT_AMOUNT,0)-NVL(TFBCP.UTILIZED_AMOUNT,0) > 0 AND (TFBCP.DEBTORPAYMENT_ID = '' OR TFBCP.DEBTORPAYMENT_ID IS NULL )
AND TFBCP.ID = #{id}
AND TFBCP.COMPANY_ID = #{companyId}
AND TFBCP.CUSTOMER_ID = #{customerId}
AND TFBCP.PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode,jdbcType=BIGINT}
ORDER BY TFBCP.CREATE_TIME DESC

SELECT ID , ID AS invoicePrepayId, COMPANY_NAME, COMPANY_ID, SYS_INVOICE_CODE AS sysInvoicePrepayNo, INVOICE_CODE AS invoicePrepayNo, CUSTOMER_ID, CUSTOMER_NAME, INVOICE_AMOUNT AS invoicePrepayAmount, STATUS, INVOICE_TYPE_CODE, INVOICE_TYPE_NAME, TAXATION_INVOICE, TAXATION_INVOICE_CODE, INVOICE_TIME AS invoicePrepayTime, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, HAS_NOT_RECEIPT_AMOUNT FROM T_FD_INVOICE
STATUS = 1 AND HAS_NOT_RECEIPT_AMOUNT > 0 and RECEIPT_STATUS <30
AND ID = #{id}
AND COMPANY_ID = #{companyId}
AND CUSTOMER_ID = #{customerId}
AND PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode,jdbcType=BIGINT}
ORDER BY CREATE_TIME DESC

SELECT ID, ID AS invoicePrepayId, CNDN_CODE AS sysInvoicePrepayNo, CNDN_TYPE, COMPANY_NAME, COMPANY_ID, CUSTOMER_ID, CUSTOMER_NAME, CNDN_TIME AS invoicePrepayTime, ELIMINATE_AMOUNT AS invoicePrepayAmount, STATUS, REMARK, PREPAYMENT_TYPE_CODE, HAS_NOT_RECEIPT_AMOUNT FROM T_FD_CREDIT_DEBIT_BILL
STATUS = 1 AND case when cndn_type = 2 and HAS_NOT_RECEIPT_AMOUNT > 0 and RECEIPT_STATUS <30 then 1 when cndn_type = 1 and (DEBTORPAYMENT_ID = '' OR DEBTORPAYMENT_ID IS NULL ) then 1 else 2 end = 1
AND ID = #{id}
AND COMPANY_ID = #{companyId}
AND CUSTOMER_ID = #{customerId}
AND PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode,jdbcType=BIGINT}
ORDER BY CREATE_TIME DESC

update.foreach:
UPDATE T_FD_INVOICE SET DEBTORPAYMENT_ID = #{item.debtorpaymentId}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, HAS_NOT_RECEIPT_AMOUNT = #{item.hasNotReceiptAmount}, RECEIPT_STATUS = #{item.receiptStatus}, UPDATE_TIME = #{item.now}
ID = #{item.invoicePrepayId}
;

UPDATE T_FD_INVOICE SET DEBTORPAYMENT_ID = '', HAS_NOT_RECEIPT_AMOUNT = #{item.hasNotReceiptAmount}, RECEIPT_STATUS = #{item.receiptStatus}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{item.now}
ID = #{item.invoicePrepayId}
;

UPDATE
T_FD_BANK_CUSTOMER_PREPAYMENT
SET
DEBTORPAYMENT_ID = #{item.debtorpaymentId},
UTILIZED_AMOUNT =#{item.invoicePrepayAmount,jdbcType=DECIMAL},
UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT},
UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR},
UPDATE_TIME = #{item.now}

    ID =  #{item.invoicePrepayId}


    ;

UPDATE T_FD_BANK_CUSTOMER_PREPAYMENT SET VOID_REMARK = #{item.voidRemark,jdbcType=VARCHAR},
STATUS= #{item.status,jdbcType=BIGINT},
DEBTORPAYMENT_ID = '', UTILIZED_AMOUNT =#{item.invoicePrepayAmount,jdbcType=DECIMAL}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{item.now}
, VOID_BY = #{item.loginUserId, jdbcType=BIGINT}, VOID_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, VOID_TIME = #{item.now}
ID = #{item.invoicePrepayId}
;

UPDATE T_FD_CREDIT_DEBIT_BILL SET DEBTORPAYMENT_ID = #{item.debtorpaymentId}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, HAS_NOT_RECEIPT_AMOUNT = #{item.hasNotReceiptAmount}, RECEIPT_STATUS = #{item.receiptStatus}, UPDATE_TIME = #{item.now}
ID = #{item.invoicePrepayId}
;

UPDATE T_FD_CREDIT_DEBIT_BILL SET DEBTORPAYMENT_ID = '', HAS_NOT_RECEIPT_AMOUNT = #{item.hasNotReceiptAmount}, RECEIPT_STATUS = #{item.receiptStatus}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{item.now}
ID = #{item.invoicePrepayId}
;

