select T1.TYPE "shipFeeType",TFID.SHIPVOYAGE_ITEM_ID FROM T_FD_INVOICE TFI LEFT JOIN T_FD_INVOICE_DETAIL TFID ON TFID.INVOICE_ID = TFI.ID LEFT JOIN T_COST_STATEMENT_DETAIL TCS ON TFID.STATEMENT_DETAIL_ID = TCS.ID LEFT JOIN T_COST_SHIP T1 ON TCS.BUSINESS_ID = T1.ID WHERE T1.TYPE = '10' AND TFI.ID IN
#{id,jdbcType=BIGINT}
GROUP BY T1.TYPE,TFID.SHIPVOYAGE_ITEM_ID

