UPDATE T_DIS_SHIPVOYAGE_ITEM
SET
PAYMENT_AMOUNT = #{paymentAmount},
PAYMENT_AMOUNT_BACK = #{paymentAmountBack}
where ID = #{id}

update T_DIS_SHIPVOYAGE  SET
PAYMENT_AMOUNT = #{paymentAmount}
where ID = #{id}

mapper.select:
SELECT tfi.id "id",tbci.cargo_info_no "cargoInfoId" FROM T_BUS_HANDOVERLIST tbh LEFT JOIN T_COST_STATEMENT tcs on tcs.HANDOVERLIST_ID = tbh.id LEFT JOIN T_COST_STATEMENT_DETAIL tcsd on tcsd.STATEMENT = tcs.id LEFT JOIN T_FD_INVOICE_DETAIL tfid on tfid.STATEMENT_DETAIL_ID =tcsd.id LEFT JOIN T_FD_INVOICE tfi on tfi.id = tfid.INVOICE_ID left join t_bus_cargo_info tbci on tbci.id = tbh.CARGO_INFO_ID
tbh.CARGO_INFO_ID = #{cargoInfoId}
and tfi.id in
#{item}

SELECT TFCDB.ID "id",tbci.cargo_info_no "cargoInfoNo" FROM T_FD_CREDIT_DEBIT_BILL TFCDB LEFT JOIN T_FD_CREDIT_DEBIT_BILL_DETAIL TFCDBD on TFCDB.id = TFCDBD.CNDN_ID LEFT JOIN T_FD_INVOICE_DETAIL TFI on TFCDBD.INVOICE_DETAIL_ID = TFI.ID LEFT JOIN T_COST_STATEMENT_DETAIL TCSD on TFI.STATEMENT_DETAIL_ID = TCSD.ID LEFT JOIN T_COST_STATEMENT TCS ON TCS.ID = TCSD.STATEMENT LEFT JOIN T_BUS_HANDOVERLIST TBH ON TBH.ID = TCS.HANDOVERLIST_ID left join t_bus_cargo_info tbci on tbci.id = tbh.cargo_info_id
TBH.CARGO_INFO_ID = #{cargoInfoId}
and TFCDB.ID in
#{item}
